import crypto from "node:crypto";
import { clearActiveStudioSession, readActiveStudioSession, writeActiveStudioSession, } from "../activeStudioSession.js";
import { navigateStudioAndAwaitAck, pollAgentSessionEvents, pollLoginEvents, } from "../agentSessionChannel.js";
import { openChromelessWindow } from "../browser.js";
import { getConfig, hasCredentials, saveCredentials } from "../config.js";
import { recordFocus } from "../frontmostApp.js";
import { emitJson } from "../output.js";
import { isValidStudioRoute } from "../studioRoutes.js";
import { createStudioSession } from "./createStudioSession.js";
import { waitForSessionReady } from "./sessionReady.js";
const SESSION_CLOSE_GRACE_PERIOD_MS = 10_000;
const LOGIN_TIMEOUT_MS = 10 * 60 * 1000;
// A no-ack only means "the window is gone" for these reasons. `blocked` means a
// LIVE tab actively refused the navigation (an app-level guard, e.g. unsaved
// changes) and `invalid-route` is a programming error — neither is a stale
// session, so they must NOT emit `not-responding` (which would prompt the user
// to clear + reopen and spawn a duplicate over a healthy tab). They surface as
// `open-failed` instead.
const UNREACHABLE_REASONS = new Set(["timeout", "push-failed", "session-ended"]);
function isUnreachable(reason) {
    return reason != null && UNREACHABLE_REASONS.has(reason);
}
export function handleStudioError(err) {
    if (err instanceof StudioNavigationError &&
        err.staleSessionId &&
        isUnreachable(err.reason)) {
        // The recorded session is believed live but unreachable (crash, sleep, or a
        // close no process witnessed). Emit the SAME structured gate event the
        // openStudioTo runner does, so every Studio-opening command participates in
        // the one gate protocol: the calling skill offers Try-again / clear-and-
        // reopen recovery uniformly instead of each command failing its own way.
        emitJson({ event: "not-responding", sessionId: err.staleSessionId });
    }
    else if (err instanceof StudioNavigationError) {
        // Blocked / invalid-route: a live tab refused, or a bad path — surface it,
        // do not offer clear-and-reopen.
        emitJson({ event: "open-failed", reason: err.blockedReason ?? err.message });
    }
    else {
        emitJson({
            event: "open-failed",
            reason: err instanceof Error ? err.message : String(err),
        });
    }
    process.exit(1);
}
export class StudioNavigationError extends Error {
    reason;
    blockedReason;
    staleSessionId;
    constructor(reason, blockedReason, staleSessionId) {
        super(blockedReason
            ? `Studio navigation failed (${reason}): ${blockedReason}`
            : `Studio navigation failed: ${reason}`);
        this.reason = reason;
        this.blockedReason = blockedReason;
        this.staleSessionId = staleSessionId;
        this.name = "StudioNavigationError";
    }
}
/**
 * Single entry point for ALL "show this path in Studio" operations.
 * Every command that needs to open or navigate Studio calls this function.
 *
 * Resolves `serviceUrl` and `apiKey` from the local config itself, so callers do
 * not thread credentials through. A null key (not authenticated) takes the
 * inline sign-in path.
 *
 * When `onEvent` is provided, starts a single event polling loop for the
 * session (whether existing or newly created). ALL events flow to the
 * callback. The caller filters to what it needs. No other poller should
 * be started by the caller.
 *
 * Authenticated. The on-disk pointer is the single source of truth:
 *   - present => navigate the existing window. If it acks, reuse it. If it does
 *     NOT ack (the tab is unreachable: crash, sleep, or a close no poller saw),
 *     throw StudioNavigationError so the caller gates (asks the user). The
 *     navigation already retries via ping-pong before reporting no-ack, so a
 *     no-ack means the tab was pinged twice and never answered. We never open a
 *     second window while a record exists.
 *   - absent => open a fresh Studio at the path and write the pointer.
 *
 * There is no `closedAt`/`endedAt` branching: a clean tab close (after the
 * refresh grace period) and a deliberate end both CLEAR the pointer (in the
 * event poller / `closeStudio`), so a closed-or-ended session is simply
 * "absent" on the next open and a fresh window opens silently. Recovery from a
 * stale pointer is explicit (`clearStudioSession`), never automatic.
 *
 * Unauthenticated (no key):
 * Opens Studio to sign-in with a redirect back to `path`. Polls for the
 * auth token, saves credentials, waits for the session to be live, then
 * starts the event poller. Fires `onLoginRequired` / `onAuthenticated`
 * callbacks so the caller can emit events.
 */
export async function openStudioTo(path, opts = {}) {
    const config = getConfig();
    const serviceUrl = config.serviceUrl;
    const apiKey = hasCredentials() ? config.apiKey : null;
    const noop = () => { };
    const restoreFocus = recordFocus();
    if (!apiKey) {
        const sessionId = crypto.randomUUID();
        // `pluginLogin=true` on the redirect is load-bearing: it is what makes the
        // authenticated Studio shell POST /api/studio/login-complete, which is the
        // only emitter of a `studio:authenticated` event carrying the token that
        // `pollLoginEvents` waits for. The top-level `session=` lets the sign-in
        // page bind the session before redirecting. Drop either and login hangs
        // until LOGIN_TIMEOUT_MS.
        const separator = path.includes("?") ? "&" : "?";
        const redirectPath = `${path}${separator}session=${encodeURIComponent(sessionId)}&pluginLogin=true`;
        const signInPath = `/studio/sign-in?redirect_url=${encodeURIComponent(redirectPath)}`;
        const signInUrl = `${serviceUrl}${signInPath}&session=${encodeURIComponent(sessionId)}`;
        openChromelessWindow(signInUrl);
        // Presentation belongs to the caller: login.js prints the URL for humans,
        // the JSONL commands carry signInUrl in the auth-required event. So don't
        // print it here (doing so double-prints for login.js).
        opts.onLoginRequired?.(sessionId, signInUrl);
        const abortController = new AbortController();
        const timer = setTimeout(() => abortController.abort(), LOGIN_TIMEOUT_MS);
        const keepalive = setInterval(() => process.stderr.write(""), 30_000);
        let loginApiKey;
        try {
            loginApiKey = await pollLoginEvents({
                serviceUrl,
                sessionId,
                abortSignal: abortController.signal,
            });
        }
        catch (err) {
            clearTimeout(timer);
            clearInterval(keepalive);
            throw err;
        }
        clearTimeout(timer);
        clearInterval(keepalive);
        saveCredentials(loginApiKey);
        opts.onAuthenticated?.(sessionId);
        if (opts.onEvent) {
            await waitForSessionReady({
                serviceUrl,
                apiKey: loginApiKey,
                sessionId,
            });
            writeActiveStudioSession({ sessionId, serviceUrl });
            const poller = startEventPoller(serviceUrl, loginApiKey, sessionId, opts.onEvent, restoreFocus);
            return {
                sessionId,
                serviceUrl,
                apiKey: loginApiKey,
                opened: true,
                ...poller,
            };
        }
        restoreFocus();
        return {
            sessionId,
            serviceUrl,
            apiKey: loginApiKey,
            opened: true,
            abort: noop,
            done: Promise.resolve(),
        };
    }
    // The on-disk pointer is the single source of truth. Present => navigate the
    // existing window; a no-ack gates (throws) rather than spawning a duplicate.
    // Absent => open a fresh window. The pointer is cleared on a witnessed close
    // or deliberate end, so a closed/ended session reads as absent here.
    const existing = readActiveStudioSession();
    if (existing) {
        const client = {
            serviceUrl: existing.serviceUrl,
            apiKey,
            sessionId: existing.sessionId,
        };
        const ack = await navigateStudioAndAwaitAck(client, path);
        if (!ack.acked) {
            // The recorded tab did not answer (timeout after ping-pong, push failed,
            // session reported ended, or a live tab actively blocked the route). Gate
            // so the caller can surface it; never silently replace a believed-live
            // window. The pointer is preserved for an explicit clear + retry.
            throw new StudioNavigationError(ack.reason ?? "unknown", ack.blockedReason, existing.sessionId);
        }
        const poller = opts.onEvent
            ? startEventPoller(existing.serviceUrl, apiKey, existing.sessionId, opts.onEvent, restoreFocus)
            : { abort: noop, done: Promise.resolve() };
        return {
            sessionId: existing.sessionId,
            serviceUrl: existing.serviceUrl,
            apiKey,
            opened: false,
            ...poller,
        };
    }
    const sessionId = crypto.randomUUID();
    const session = await createStudioSession({
        serviceUrl,
        apiKey,
        sessionId,
        initialPath: path,
        clientHeaders: opts.clientHeaders,
    });
    const poller = opts.onEvent
        ? startEventPoller(session.serviceUrl, apiKey, session.sessionId, opts.onEvent, restoreFocus)
        : { abort: noop, done: Promise.resolve() };
    return {
        sessionId: session.sessionId,
        serviceUrl: session.serviceUrl,
        apiKey,
        opened: true,
        ...poller,
    };
}
/**
 * Starts the single event polling loop for a Studio session. Returns an
 * abort function.
 *
 * The pointer is removed ONLY on proof the window is gone: a
 * `studio:session-closed` event (the browser's `beforeunload` beacon, plus the
 * explicit close paths). A `studio:session-ended` ("conclude" / "return to agent
 * & close") is NOT proof — `closeSession` emits it and then *tries*
 * `window.close()`, which the browser can refuse — so on its own it never
 * clears. We wait for the `session-closed` that normally follows and clear
 * there. The only other clear in the whole system is the explicit
 * `clearStudioSession` recovery after a not-responding gate.
 *
 * Commands key on `session-ended`, so the real `session-ended` is swallowed and
 * a synthetic one is emitted at confirmed-closure time — commands see exactly
 * one, and they need no changes.
 *
 * Timing: a deliberate close (`session-ended` then `session-closed`) clears and
 * terminates immediately. A bare `session-closed` (manual tab close) waits the
 * grace window so a refresh (`session-started`) can cancel it. A `session-ended`
 * with NO following `session-closed` (a refused `window.close()`) terminates the
 * command after the grace window WITHOUT clearing — the window may still be
 * alive, so the pointer is kept (next open reuses or, if truly gone, gates).
 */
function startEventPoller(serviceUrl, apiKey, sessionId, onEvent, restoreFocus) {
    const abortController = new AbortController();
    let graceTimer = null;
    let sawSessionEnded = false;
    const clearGraceTimer = () => {
        if (graceTimer) {
            clearTimeout(graceTimer);
            graceTimer = null;
        }
    };
    // `clear` gates the only file removal in the poller: true only once we have a
    // `session-closed` (proof the window is gone). `baseEvent` seeds the synthetic
    // `session-ended` handed to the command so its existing terminal logic runs.
    const terminate = (clear, baseEvent) => {
        graceTimer = null;
        if (clear) {
            clearActiveStudioSession(sessionId);
        }
        restoreFocus();
        onEvent({ ...baseEvent, type: "studio:session-ended" });
        abortController.abort();
    };
    const done = pollAgentSessionEvents({
        serviceUrl,
        apiKey,
        sessionId,
        abortSignal: abortController.signal,
        onEvent: (event) => {
            if (event.type === "studio:session-closed") {
                // Authoritative proof the window is gone. Supersede any pending
                // session-ended fallback and clear.
                clearGraceTimer();
                if (sawSessionEnded) {
                    // Deliberate close, now confirmed: clear and terminate at once.
                    terminate(true, event);
                }
                else {
                    // Possibly a refresh: wait the grace window so a session-started can
                    // cancel; otherwise clear (the tab really closed).
                    graceTimer = setTimeout(() => {
                        terminate(true, event);
                    }, SESSION_CLOSE_GRACE_PERIOD_MS);
                }
                return;
            }
            if (event.type === "studio:session-started") {
                if (graceTimer) {
                    clearGraceTimer();
                    console.error("Studio reconnected after page refresh");
                }
                sawSessionEnded = false;
                return;
            }
            if (event.type === "studio:session-ended") {
                // Not proof of closure. Note it and wait for the session-closed that
                // normally follows. If none arrives within the grace window (a refused
                // window.close()), terminate the command WITHOUT clearing — the pointer
                // is kept because the window may still be alive. Focus is restored by
                // terminate() (always runs on close or the fallback), so don't restore
                // here too — that double-fired in the deliberate-close path.
                sawSessionEnded = true;
                if (!graceTimer) {
                    graceTimer = setTimeout(() => {
                        terminate(false, event);
                    }, SESSION_CLOSE_GRACE_PERIOD_MS);
                }
                return;
            }
            if (event.type === "studio:not-member") {
                restoreFocus();
                onEvent(event);
                abortController.abort();
                return;
            }
            if (event.type === "studio:return-to-agent" ||
                event.type === "studio:edit-with-agent") {
                restoreFocus();
            }
            onEvent(event);
        },
        onError: (err) => {
            console.error(`studio agent-event poll: ${err.message}`);
        },
    }).catch((err) => {
        if (!abortController.signal.aborted) {
            console.error(`studio agent-event poll terminated: ${err.message}`);
        }
    });
    return { abort: () => abortController.abort(), done };
}
/**
 * CLI runner. Parses args and calls openStudioTo.
 */
export async function runOpenStudioTo(platform) {
    let path = process.argv.slice(2).find((a) => !a.startsWith("--"));
    if (!path) {
        console.error("Usage: openStudioTo <path>");
        process.exit(1);
    }
    if (!path.startsWith("/studio")) {
        path = "/studio";
    }
    if (!isValidStudioRoute(path)) {
        console.error(`Studio route not allowed: ${path}`);
        process.exit(1);
    }
    try {
        const result = await openStudioTo(path, {
            clientHeaders: {
                "x-bitfab-client-name": platform.cliBinary,
                "x-bitfab-client-display-name": platform.displayName,
            },
            onLoginRequired: (sessionId, signInUrl) => {
                emitJson({ event: "auth-required", sessionId, signInUrl });
            },
            onAuthenticated: (sessionId) => {
                emitJson({ event: "authenticated", sessionId });
            },
            onEvent: (event) => {
                const data = event.data;
                const payload = {
                    event: event.type.replace("studio:", ""),
                    sessionId: result.sessionId,
                };
                if (data.datasetId) {
                    payload.datasetId = data.datasetId;
                }
                if (data.path) {
                    payload.path = data.path;
                }
                if (data.search) {
                    payload.search = data.search;
                }
                if (data.token) {
                    payload.token = data.token;
                }
                emitJson(payload);
            },
        });
        if (result.opened) {
            emitJson({ event: "started", sessionId: result.sessionId });
        }
        else {
            emitJson({ event: "navigated", sessionId: result.sessionId, path });
        }
        const shutdown = () => {
            result.abort();
            process.exit(0);
        };
        process.on("SIGINT", shutdown);
        process.on("SIGTERM", shutdown);
        await result.done;
    }
    catch (err) {
        if (err instanceof StudioNavigationError &&
            err.staleSessionId &&
            isUnreachable(err.reason)) {
            emitJson({
                event: "not-responding",
                sessionId: err.staleSessionId,
                path,
            });
        }
        else if (err instanceof StudioNavigationError) {
            // Blocked / invalid-route: a live tab refused, or a bad path. Surface it
            // rather than prompting a clear-and-reopen that would duplicate a healthy
            // window.
            emitJson({
                event: "open-failed",
                sessionId: "none",
                reason: err.blockedReason ?? err.message,
            });
        }
        else {
            emitJson({
                event: "open-failed",
                sessionId: "none",
                reason: err.message,
            });
        }
        process.exit(1);
    }
}
